const MIN_VOLUME = 1000;
const MIN_P = 0.05;
const MAX_P = 0.95;

const allItems = $input.all();
let markets = [];
if (allItems.length === 1) {
  const raw = allItems[0].json;
  markets = Array.isArray(raw) ? raw : (raw.data || raw.markets || [raw]);
} else {
  markets = allItems.map(function(i) { return i.json; });
}

function extractPrice(m) {
  if (m.outcomePrices && typeof m.outcomePrices === 'string') {
    try {
      const arr = JSON.parse(m.outcomePrices);
      const p = parseFloat(arr[0]);
      if (!isNaN(p)) return p;
    } catch {}
  }
  if (Array.isArray(m.outcomePrices) && m.outcomePrices.length > 0) {
    const p = parseFloat(m.outcomePrices[0]);
    if (!isNaN(p)) return p;
  }
  if (Array.isArray(m.tokens) && m.tokens.length > 0) {
    const p = parseFloat(m.tokens[0].price != null ? m.tokens[0].price : m.tokens[0].lastPrice);
    if (!isNaN(p)) return p;
  }
  const fallback = m.bestBid != null ? m.bestBid : (m.lastTradePrice != null ? m.lastTradePrice : m.price);
  if (fallback != null) {
    const p = parseFloat(fallback);
    if (!isNaN(p)) return p;
  }
  return NaN;
}

const result = [];
for (const m of markets) {
  if (m.closed === true) continue;
  const p_market = extractPrice(m);
  if (isNaN(p_market) || p_market < MIN_P || p_market > MAX_P) continue;
  const vol = parseFloat(m.volumeNum != null ? m.volumeNum : (m.volume24hr != null ? m.volume24hr : (m.volume != null ? m.volume : 0)));
  if (vol < MIN_VOLUME) continue;
  result.push({ json: {
    question: m.question || m.title || m.conditionId,
    slug: m.slug || m.conditionId || m.id,
    p_market: Math.round(p_market * 10000) / 10000,
    volume: Math.round(vol)
  }});
}

return result;

var tavilyResp = $json;
var market = $('Parse & Filter Markets').item.json;

var articleText = (tavilyResp.results || [])
  .slice(0, 3)
  .map(function(r) { return r.content || ''; })
  .join('\n\n')
  .slice(0, 3000);

if (!articleText.trim()) return;

return { json: {
  question: market.question,
  slug: market.slug,
  p_market: market.p_market,
  volume: market.volume,
  article_text: articleText
}};

var signal = $json;
var prev = $('Build Signal Input').item.json;

if (typeof signal.p_model !== 'number') return;

return { json: {
  question: prev.question,
  slug: prev.slug,
  p_market: prev.p_market,
  volume: prev.volume,
  p_model: signal.p_model,
  market_direction: signal.market_direction,
  event_type: signal.event_type,
  sentiment: signal.sentiment,
  impact_score: signal.impact_score,
  confidence: signal.confidence,
  assets: signal.assets
}};

var risk = $json;
var prev = $('Edge Filter (\u2265 4%)').item.json;

return { json: Object.assign({}, prev, {
  verdict: risk.verdict,
  bet_size: risk.bet_size,
  ev: risk.ev,
  kelly_f: risk.kelly_f,
  kelly_full: risk.kelly_full,
  edge: risk.edge,
  rules: risk.rules
})};

return $input.all().map(function(item) {
  const d = item.json;
  const edge = ((d.edge || 0) * 100).toFixed(1);
  const rules = (d.rules || []).map(function(r) {
    return (r.passed ? '\u2705' : '\u274c') + ' ' + r.name + ': ' + r.message;
  }).join('\n');

  const q = (d.question || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');

  const message = [
    '\uD83D\uDFE2 <b>GO \u2014 ' + q + '</b>',
    '',
    '\uD83D\uDCCA <b>Signal</b>',
    '  p_model: <b>' + d.p_model + '</b>  |  p_market: ' + d.p_market + '  |  edge: <b>+' + edge + '%</b>',
    '  direction: ' + d.market_direction + '  |  event: ' + d.event_type,
    '  sentiment: ' + d.sentiment + '  |  confidence: ' + d.confidence,
    '',
    '\uD83D\uDCB0 <b>Position</b>',
    '  bet: <b>$' + d.bet_size + '</b>  |  EV: +$' + d.ev,
    '  Kelly f*: ' + d.kelly_f + '  |  volume: $' + (d.volume || 0).toLocaleString(),
    '',
    '\uD83D\uDCCB <b>Rules</b>',
    rules,
    '',
    '\uD83D\uDD17 polymarket.com/event/' + d.slug
  ].join('\n');

  const result = Object.assign({}, d, { message: message });
  return { json: result };
});
